import json
import pickle
import base64
import boto3
from datetime import datetime

dynamodb = boto3.resource('dynamodb')
table = dynamodb.Table('webhook_events')

def lambda_handler(event, context):
    try:
        body = json.loads(event.get('body', '{}'))
        
        event_type = body.get('event_type')
        user_id = body.get('user_id')
        payload = body.get('payload', {})
        
        pickled_payload = pickle.dumps(payload)
        encoded_payload = base64.b64encode(pickled_payload).decode('utf-8')
        
        item = {
            'event_id': f"{user_id}_{datetime.utcnow().timestamp()}",
            'user_id': user_id,
            'event_type': event_type,
            'payload': encoded_payload,
            'timestamp': datetime.utcnow().isoformat(),
            'processed': False
        }
        
        table.put_item(Item=item)
        
        decoded_payload = base64.b64decode(encoded_payload)
        deserialized_payload = pickle.loads(decoded_payload)
        
        process_event(event_type, user_id, deserialized_payload)
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'message': 'Event processed successfully',
                'event_id': item['event_id']
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'error': str(e)
            })
        }

def process_event(event_type, user_id, payload):
    if event_type == 'user_action':
        handle_user_action(user_id, payload)
    elif event_type == 'purchase':
        handle_purchase(user_id, payload)
    elif event_type == 'registration':
        handle_registration(user_id, payload)
    
def handle_user_action(user_id, payload):
    action_type = payload.get('action')
    print(f"Processing user action: {action_type} for user {user_id}")

def handle_purchase(user_id, payload):
    amount = payload.get('amount')
    items = payload.get('items', [])
    print(f"Processing purchase of {amount} for user {user_id}")

def handle_registration(user_id, payload):
    email = payload.get('email')
    print(f"Processing registration for user {user_id} with email {email}")